={{ JSON.stringify((() => {
  const clamp01 = (x) => (x < 0 ? 0 : x > 1 ? 1 : x);

  // allow the current item JSON itself to be an array
  const root = Array.isArray($json) ? ($json[0] ?? {}) : $json;

  const id = root.id ?? root.entry_id ?? null;
  if (!id) throw new Error('db/update: missing id (expected $json.id or $json.entry_id)');

  let t1 = root.t1 ?? root;
  if (Array.isArray(t1)) t1 = t1[0];
  if (!t1 || typeof t1 !== 'object') throw new Error('db/update: missing t1 object');

  const topic_primary = String(t1.topic_primary ?? '').trim() || null;
  const topic_secondary = String(t1.topic_secondary ?? '').trim() || null;
  const gist = String(t1.gist ?? '').trim() || null;

  const tpcRaw = t1.topic_primary_confidence;
  const tscRaw = t1.topic_secondary_confidence;

  const topic_primary_confidence =
    (tpcRaw === null || tpcRaw === undefined || tpcRaw === '') ? null : clamp01(Number(tpcRaw));

  const topic_secondary_confidence =
    (tscRaw === null || tscRaw === undefined || tscRaw === '') ? null : clamp01(Number(tscRaw));

  let keywords = Array.isArray(t1.keywords)
    ? t1.keywords.map(x => String(x ?? '').trim()).filter(Boolean)
    : [];
  keywords = Array.from(new Set(keywords));
  if (keywords.length > 12) keywords = keywords.slice(0, 12);

  const numOrNull = (v) => (v === null || v === undefined || v === '') ? null : Number(v);

  const body = {
    id,
    topic_primary,
    topic_primary_confidence,
    topic_secondary,
    topic_secondary_confidence,
    keywords: keywords.length ? keywords : null,
    gist,

    quality_score: numOrNull(t1.quality_score),
    clean_word_count: numOrNull(t1.clean_word_count),
    clean_char_count: numOrNull(t1.clean_char_count),
    link_count: numOrNull(t1.link_count),
    link_ratio: numOrNull(t1.link_ratio),
    retrieval_excerpt: String(t1.retrieval_excerpt ?? '').trim() || null,

    enrichment_status: 'done',
    enrichment_model: root.enrichment_model ?? 'unknown',
    prompt_version: root.prompt_version ?? 'unknown',

    metadata: {
      t1_raw: t1,
      t1_flags: (t1.flags && typeof t1.flags === 'object') ? t1.flags : null
    },

    returning: [
      "entry_id",
      "id",
      "created_at",
      "source",
      "intent",
      "content_type",
      "url_canonical",
      "COALESCE(title,'') AS title",
      "COALESCE(author,'') AS author",
      "clean_text",
      "capture_text",
      "topic_primary",
      "topic_secondary",
      "gist",
      "COALESCE(char_length(clean_text), 0) AS clean_len",
      "array_length(keywords,1) AS kw_count",
      "enrichment_status"
    ]
  };

  // Don’t overwrite with empty strings :contentReference[oaicite:3]{index=3}
  const clean = String(root.clean_text ?? "").trim();
  if (clean) body.clean_text = clean;

  return body;  // required :contentReference[oaicite:4]{index=4}
})()) }}

={{ JSON.stringify((() => {
  const body = {};

  // scalar fields (null when missing)
  body.title = $json.title ?? null;
  body.author = $json.author ?? null;

  // only include clean_text if non-empty (avoid overwriting with "")
  const clean = String($json.clean_text ?? "").trim();
  if (clean) body.clean_text = clean;

  return body;
})()) }}
